/**
 * @summary List fill orders
 */
export const getListFillsUrl = (params?: ListFillsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/fills?${stringifiedParams}`
    : `/api/fills`;
};

export const listFills = async (
  params?: ListFillsParams,
  options?: RequestInit,
): Promise<FillOrder[]> => {
  return customFetch<FillOrder[]>(getListFillsUrl(params), {
    ...options,
    method: "GET",
  });
};

